for (uint256 i = 0; i < groups_.length; ++i) {
    roles_ = getGroupRoles(groups_[i]);

    for (uint256 j = 0; j < roles_.length; ++j) {
        string memory role_ = roles_[j];

        if (_isDisallowed(role_, resource_, permission_)) {
            return false;
        }

        isAllowed_ = isAllowed_ || _isAllowed(role_, resource_, permission_);
    }
}

for (uint256 i = 0; i < signers_.length; ++i) {
    address signer_ = signers_[i];

    if (!$.signers.contains(signer_)) revert InvalidSigner(signer_);

    // get the topmost byte for bloom filtering
    uint256 bitKey_ = 2 ** (uint256(uint160(signer_)) >> 152);

    if (bitMap_ & bitKey_ != 0) revert DuplicateSigner(signer_);

    bitMap_ |= bitKey_;
}

